<?php
namespace OnKupon\Agent\Learning; class StrategyWeightsRepository { public function update(string $dimension,string $variant,float $delta): void { global $wpdb; $table=$wpdb->prefix.'onkupon_agent_learning_weights'; $row=$wpdb->get_row($wpdb->prepare("SELECT * FROM $table WHERE dimension=%s AND variant_key=%s",$dimension,$variant)); if($row){ $wpdb->update($table,['weight'=>max(0.01,(float)$row->weight+$delta),'updated_at'=>current_time('mysql')],['id'=>$row->id]); } else { $wpdb->insert($table,['dimension'=>$dimension,'variant_key'=>$variant,'weight'=>max(0.01,1+$delta),'updated_at'=>current_time('mysql'),'metadata_json'=>'{}']); } } public function all(): array { global $wpdb; return $wpdb->get_results("SELECT * FROM {$wpdb->prefix}onkupon_agent_learning_weights",ARRAY_A) ?: []; } }